TANTRA_DATA = [
    {"id": "chakra-activation", "name": "Chakra Activation Sequence", "category": "energy", "description": "A systematic practice of awakening each of the seven major chakras through visualization, mantra, and breath. This is the foundational practice of tantric energy work — learning to feel, direct, and harmonize the energy centers along the spine.", "duration": "30 min", "level": "Intermediate", "instructions": ["Sit in a comfortable position with spine erect, hands in Gyan Mudra", "Begin with 3 deep breaths to center yourself and set your intention", "Root Chakra (Muladhara): Visualize a spinning red sphere at the base of your spine. Feel its warmth and stability. Chant LAM 7 times slowly", "Sacral Chakra (Svadhisthana): Visualize a glowing orange sphere below the navel. Feel fluidity and creative energy. Chant VAM 7 times", "Solar Plexus (Manipura): Visualize a brilliant yellow sun at the navel center. Feel personal power igniting. Chant RAM 7 times", "Heart Chakra (Anahata): Visualize an emerald green sphere at the heart center. Feel unconditional love radiating. Chant YAM 7 times", "Throat Chakra (Vishuddha): Visualize a bright blue sphere at the throat. Feel truth and expression opening. Chant HAM 7 times", "Third Eye (Ajna): Visualize a deep indigo sphere between the eyebrows. Feel intuition awakening. Chant OM 7 times", "Crown Chakra (Sahasrara): Visualize a thousand-petaled violet or white lotus above the head. Sit in silence for 5 minutes", "Feel all seven chakras connected by a luminous column of light running along your spine. You are a pillar of living light"], "color": "#D8B4FE", "chakras": ["Root", "Sacral", "Solar Plexus", "Heart", "Throat", "Third Eye", "Crown"]},
    {"id": "kundalini-breathwork", "name": "Kundalini Breath of Fire", "category": "breathwork", "description": "A rapid rhythmic breathing technique that activates kundalini energy, detoxifies the blood, energizes the nervous system, and creates a powerful field of electromagnetic energy. This is one of the most fundamental and transformative practices in Kundalini Yoga.", "duration": "15 min", "level": "Advanced", "instructions": ["Sit in easy pose (Sukhasana) with spine perfectly straight", "Rest hands on knees in Gyan Mudra, palms facing upward", "Begin rapid rhythmic breathing through the nose — 2 to 3 breaths per second", "The emphasis is on the exhale — snap the navel point inward on each exhale. The inhale happens naturally", "Start with 30-second rounds, building gradually to 1 minute, then 3 minutes", "Pump the navel point vigorously with each exhale — this is the engine of the practice", "After each round, inhale deeply and hold the breath. Apply Mula Bandha (root lock) — contract the perineum, pull navel to spine", "Hold as long as comfortable, then exhale slowly through the nose", "Rest and feel the energy buzzing through your body. Notice the tingling in your hands and face", "Practice 3 to 7 rounds. End with 3 long, deep breaths. Sit in stillness and observe the activated energy"], "color": "#EF4444", "chakras": ["Root", "Sacral", "Solar Plexus"]},
    {"id": "heart-opening", "name": "Heart Opening Practice", "category": "energy", "description": "A gentle but profound practice combining breath, visualization, and mantra to dissolve the armor around the heart chakra and cultivate the capacity for unconditional love — love without conditions, expectations, or boundaries.", "duration": "20 min", "level": "Beginner", "instructions": ["Sit comfortably with both palms resting on your heart center, one on top of the other", "Take 7 slow, deep breaths, feeling your chest rise and fall beneath your hands", "Visualize a green emerald sphere of light glowing in your heart center, pulsing with each heartbeat", "With each breath, see this light expanding — first filling your chest, then your whole body, then the room", "Silently repeat with full feeling: I am love. I give love freely. I receive love gratefully", "Chant YAM — the heart chakra seed mantra — 21 times. Feel the vibration in your chest", "Now send love to yourself — your body, your struggles, your imperfections. Forgive yourself completely", "Send love to those closest to you. See their faces illuminated by your heart light", "Expand further — send love to all beings, all creatures, all of existence", "Rest in the open-hearted awareness for 5 minutes. Seal by pressing palms together at heart, whispering Namaste"], "color": "#22C55E", "chakras": ["Heart"]},
    {"id": "mantra-meditation", "name": "Sacred Mantra Meditation", "category": "mantra", "description": "The ancient science of sacred sound vibration. Mantras are not merely words — they are precise sound frequencies that alter brain chemistry, purify the energy body, and connect the practitioner with specific divine energies. This practice moves from external chanting to whispered repetition to silent internal vibration.", "duration": "20 min", "level": "Beginner", "instructions": ["Choose your mantra: Om (universal consciousness), Om Mani Padme Hum (compassion), So Hum (I am That), Om Namah Shivaya (I bow to my inner Self), or Sat Nam (Truth is my Name)", "Sit with spine erect, eyes gently closed, hands in Gyan Mudra", "Stage 1 — Vaikhari (audible): Chant the mantra aloud 21 times. Feel the physical vibration in your throat, chest, and skull", "Stage 2 — Upamshu (whispered): Whisper the mantra 21 times. Only your lips move. The vibration becomes more subtle and internal", "Stage 3 — Manasika (silent): Repeat the mantra mentally for 10 minutes. No lip movement. The mantra now vibrates in your mind only", "Use a mala (108 beads) if available — let each bead pass through your fingers with each repetition", "When the mind wanders to thoughts, gently return to the mantra without judgment. The wandering IS the practice", "Feel the mantra becoming autonomous — it begins to repeat itself without effort", "Stage 4 — Ajapa Japa: The mantra dissolves. Sit in the silence that the mantra created. This is the deepest state", "Close by chanting Om three times aloud. Feel the vibration settling into every cell of your body"], "color": "#FCD34D", "chakras": ["Throat", "Crown"]},
    {"id": "tantric-breathwork", "name": "Tantric Circular Breathing", "category": "breathwork", "description": "A connected breathing technique where there is no pause between inhale and exhale, creating a continuous circle of energy. This practice can produce profound altered states, emotional release, and energetic openings. Used in various traditions including Rebirthing, Holotropic Breathwork, and classical Tantra.", "duration": "25 min", "level": "Intermediate", "instructions": ["Lie down on your back or sit comfortably — lying down is recommended for beginners", "Begin breathing through the mouth with absolutely no pause between inhale and exhale", "The breath forms a continuous circle — inhale flows directly into exhale flows directly into inhale", "Inhale fully into the belly first, then expand into the chest (two-part inhale)", "Exhale with a relaxed release — do NOT force the exhale. Let it fall out naturally", "Maintain a steady, rhythmic pace — not too fast, not too slow. Find your natural circle", "After 10 minutes, you may feel tingling in your hands and face — this is normal and safe", "Waves of energy, emotion, or temperature changes may arise. Allow everything. Resist nothing", "Continue the connected breathing for 20 minutes total. Trust the process", "Transition slowly to natural nasal breathing. Rest for 5-10 minutes of integration in stillness. Journal any insights"], "color": "#06B6D4", "chakras": ["Sacral", "Heart", "Crown"]},
    {"id": "third-eye-activation", "name": "Third Eye Activation", "category": "energy", "description": "A focused practice to awaken the Ajna chakra — the seat of intuition, inner vision, and the command center of the subtle body. The third eye is the gateway between the physical and spiritual dimensions. When activated, it grants access to inner knowing, psychic perception, and direct spiritual insight.", "duration": "20 min", "level": "Intermediate", "instructions": ["Sit in a completely dark or very dimly lit room for maximum effect", "Apply gentle pressure between your eyebrows with your middle finger for 30 seconds — this activates the physical location", "Close your eyes and redirect your internal gaze upward to the third eye point between and slightly above the eyebrows", "Practice alternate nostril breathing (Nadi Shodhana) for 5 minutes to balance the left and right energy channels", "Switch to a 4-4-4 breath: inhale 4 counts, hold 4 counts, exhale 4 counts. Direct breath energy to the third eye", "Chant OM 21 times, feeling the vibration concentrate at the point between your brows", "Visualize a deep indigo sphere of light pulsing at your third eye, growing brighter with each OM", "Practice Trataka (candle gazing): gaze at a candle flame at eye level for 5 minutes without blinking. When tears come, close your eyes", "With eyes closed after Trataka, observe the afterimage of the flame at your third eye. Follow this light", "Sit in the inner vision for 5-10 minutes. Whatever images, colors, or impressions arise — observe without attachment"], "color": "#8B5CF6", "chakras": ["Third Eye"]},
    {"id": "nadi-shodhana", "name": "Nadi Shodhana Pranayama", "category": "breathwork", "description": "Alternate nostril breathing — one of the most powerful and balancing pranayama techniques. Nadi means channel and Shodhana means purification. This practice purifies the 72,000 energy channels (nadis) in the subtle body, balances the solar (Pingala) and lunar (Ida) channels, and prepares the central channel (Sushumna) for the rise of Kundalini.", "duration": "15 min", "level": "Beginner", "instructions": ["Sit comfortably with spine erect. Use Vishnu Mudra on the right hand: fold index and middle fingers to palm, use thumb and ring finger", "Close the right nostril with your right thumb. Inhale slowly through the left nostril for 4 counts", "Close both nostrils (thumb on right, ring finger on left). Hold the breath for 4 counts", "Release the right nostril. Exhale slowly through the right nostril for 8 counts", "Inhale through the right nostril for 4 counts", "Close both nostrils. Hold for 4 counts", "Release the left nostril. Exhale through the left for 8 counts. This completes ONE round", "Practice 9 to 12 rounds to start, building to 20+ rounds with experience", "The exhale should always be twice as long as the inhale (4:4:8 ratio). Advanced: 4:16:8", "After completing all rounds, sit with both nostrils open and observe the balanced, peaceful state of mind"], "color": "#2DD4BF", "chakras": ["Third Eye", "Crown"]},
    {"id": "trataka", "name": "Trataka (Candle Gazing)", "category": "energy", "description": "One of the six classical purification practices (Shatkarmas) of Hatha Yoga. Trataka means 'to gaze steadily.' By fixing the eyes on a single point (traditionally a candle flame), the mind becomes concentrated, the eyes are purified, and the third eye is activated. This is the bridge between physical yoga practice and meditation.", "duration": "15 min", "level": "Beginner", "instructions": ["Place a candle at eye level, about an arm's length away. The room should be dark and draft-free", "Sit in a stable meditation posture with spine erect", "Gaze steadily at the very tip of the candle flame — the brightest point — without blinking", "Keep the eyes relaxed, not strained. The gaze should be soft but unwavering", "When tears begin to flow, this is the cleansing effect — allow it. Tears purify the eyes and release stored emotions", "After 3-5 minutes of gazing (or when tears become too strong), close your eyes", "Observe the afterimage of the flame on the inner screen of your closed eyes", "Try to hold this afterimage at the point of the third eye. If it moves, gently bring it back", "When the afterimage fades, open your eyes and repeat the external gazing", "Practice for 3 rounds. End by palming: rub palms together vigorously and cup them over closed eyes for 1 minute"], "color": "#F59E0B", "chakras": ["Third Eye"]},
    {"id": "yoga-nidra", "name": "Yoga Nidra (Yogic Sleep)", "category": "energy", "description": "The practice of conscious sleep — a systematic method of complete physical, mental, and emotional relaxation while maintaining awareness. One hour of Yoga Nidra is equivalent to 4 hours of regular sleep. This tantric practice accesses the hypnagogic state between waking and sleeping, where deep healing and transformation occur.", "duration": "30 min", "level": "Beginner", "instructions": ["Lie down in Shavasana (corpse pose) on your back. Cover yourself with a blanket. Use an eye pillow if available", "Set your Sankalpa (intention/resolve) — a short, positive statement in present tense. Example: I am at peace. I am healed", "Rotate awareness through the body systematically: right hand thumb, index finger, middle finger, ring finger, little finger, palm, back of hand, wrist, forearm, elbow, upper arm, shoulder, armpit, right side of torso, right hip, thigh, knee, calf, ankle, heel, sole, top of foot, right big toe through little toe", "Repeat for the left side of the body in the same sequence", "Become aware of the back body, the front body, the whole body as a single field of sensation", "Awareness of breath — count breaths backward from 27 to 1. If you lose count, restart from 27", "Visualization sequence: imagine a clear blue sky, a still lake, a golden sunrise, a candle flame, a vast starfield", "Return to your Sankalpa — repeat it three times with full conviction and feeling", "Begin to externalize awareness: sounds in the room, weight of the body, sensation of breathing", "Gently move fingers and toes. Roll to your right side. Slowly sit up. The practice is complete"], "color": "#93C5FD", "chakras": ["Crown", "Third Eye"]},
    {"id": "five-elements", "name": "Five Elements Balancing", "category": "energy", "description": "A comprehensive practice for balancing all five elements (Pancha Tattva) within the body: Earth, Water, Fire, Air, and Ether. Each element corresponds to a chakra, finger, organ system, and quality of consciousness. When all five are in balance, health is perfect and consciousness is clear.", "duration": "25 min", "level": "Intermediate", "instructions": ["Sit in meditation posture. Begin with 5 minutes of natural breath observation", "Earth Element (Prithvi): Focus on the Root Chakra. Touch ring finger to thumb (Prithvi Mudra). Chant LAM. Visualize a yellow square. Feel stability, solidity, and groundedness for 3 minutes", "Water Element (Jala): Focus on the Sacral Chakra. Touch little finger to thumb (Varuna Mudra). Chant VAM. Visualize a silver crescent moon. Feel fluidity, adaptability, and creative flow for 3 minutes", "Fire Element (Agni): Focus on the Solar Plexus. Touch ring finger base with thumb (Surya Mudra). Chant RAM. Visualize a red triangle. Feel warmth, power, and transformative energy for 3 minutes", "Air Element (Vayu): Focus on the Heart Chakra. Touch index finger base with thumb (Vayu Mudra). Chant YAM. Visualize a hexagram (Star of David). Feel lightness, freedom, and movement for 3 minutes", "Ether Element (Akasha): Focus on the Throat Chakra. Touch middle finger to thumb (Shuni Mudra). Chant HAM. Visualize a circle. Feel spaciousness, emptiness, and infinite potential for 3 minutes", "Integration: Feel all five elements in balance within your body. You are Earth, Water, Fire, Air, and Space. Complete and whole", "Close with 3 rounds of Nadi Shodhana (alternate nostril breathing) to seal the practice"], "color": "#86EFAC", "chakras": ["Root", "Sacral", "Solar Plexus", "Heart", "Throat"]},
]
